namespace sv_b04ed00e37c44c2cbc0fd66d47efc125.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

.channel-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 8px 16px;
    border: none;
    background: transparent;
    color: #ccc;
    cursor: pointer;
    text-align: left;
    border-radius: 4px;
    margin: 1px 0;
    font-family: inherit;
    font-size: inherit;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.15);
    color: #fff;
    font-weight: 600;
}

.channel-info {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.channel-name {
    font-size: 0.95rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
    margin-left: 8px;
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #2c2f33;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #40444b;
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
}

.message-input textarea:focus {
    border-color: #4a90d9;
    box-shadow: 0 0 0 2px rgba(74, 144, 217, 0.2);
}

.send-btn {
    padding: 8px 20px;
    background: #4a90d9;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    align-self: flex-end;
    font-family: inherit;
}

.send-btn:hover:not(:disabled) {
    background: #357abd;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

