arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-area @(_threadOpen ? "with-thread" : "")">
        @if (_selectedChannel is not null)
        {
            <div class="area-header">
                <h3># @_selectedChannel.Name</h3>
                <span class="channel-description">@_selectedChannel.Description</span>
            </div>
            <div class="message-list" @ref="_messageListRef">
                <div @ref="_scrollSentinel" class="scroll-sentinel"></div>
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <MessageItem Message="msg"
                                 ThreadSummary="_threadSummaries.GetValueOrDefault(msg.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="(emoji) => AddReaction(msg.Id, emoji)" />
                }
            </div>
            <MessageInput OnSend="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];
    private bool _loadingMore;
    private bool _allMessagesLoaded;
    private bool _observerNeeded;
    private const int PageSize = 50;

    private ElementReference _scrollSentinel;
    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotnetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            _dotnetRef = DotNetObjectReference.Create(this);
        }

        if (_observerNeeded && _jsModule is not null && _dotnetRef is not null)
        {
            _observerNeeded = false;
            await _jsModule.InvokeVoidAsync("initScrollObserver", _scrollSentinel, _dotnetRef);
        }
    }

    private async Task SelectChannel(int channelId)
    {
