        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            _dotnetRef = DotNetObjectReference.Create(this);
        }

        if (_observerNeeded && _jsModule is not null && _dotnetRef is not null)
        {
            _observerNeeded = false;
            await _jsModule.InvokeVoidAsync("initScrollObserver", _scrollSentinel, _dotnetRef);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _allMessagesLoaded = _messages.Count < PageSize;
        ComputeThreadSummaries();
        CloseThreadInternal();
        _observerNeeded = true;
        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private void ComputeThreadSummaries()
    {
        _threadSummaries.Clear();
        var replies = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replies)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;
        _threadReplies = await ChatService.GetThreadAsync(messageId);
        _threadOpen = true;
    }

    private void CloseThreadInternal()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private void CloseThread() => CloseThreadInternal();

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(msg);
        ComputeThreadSummaries();
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(msg);
        _messages.Add(msg);
        ComputeThreadSummaries();
    }

    private async Task AddReaction(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        // Re-fetch current page of messages to refresh reaction state
        _messages = await ChatService.GetMessagesAsync(
            _selectedChannelId, 0, _messages.Count);
        ComputeThreadSummaries();
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (_loadingMore || _allMessagesLoaded || _selectedChannel is null) return;
        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId, _messages.Count, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;
        _messages.InsertRange(0, older);
        ComputeThreadSummaries();
        _loadingMore = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotnetRef?.Dispose();
    }
}

