toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.main-area.with-thread {
    /* Main area shrinks when thread is open; flex handles it */
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.area-header h3 {
    margin: 0 0 2px 0;
    font-size: 1.1rem;
    color: #1a1a1a;
}

.channel-description {
    font-size: 0.8rem;
    color: #999;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.scroll-sentinel {
    height: 1px;
    width: 100%;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 0.85rem;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

